1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioResult {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	
57	const BASE_PREMIUM: Record<string, number> = {
58	  sword: 100,
59	  amulet: 60,
60	  staff: 80,
61	  potion: 40,
62	};
63	
64	const basePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
65	
66	const sumBasePremiums = (items: Item[]): number =>
67	  items.reduce((sum, item) => sum + basePremium(item), 0);
68	
69	const quotePremium = (items: Item[]): number =>
70	  sumBasePremiums(items) + PROCESSING_FEE;
71	
72	export const runScenario = (scenario: Scenario): ScenarioResult => {
73	  const results = scenario.steps.map((step): StepResult => {
74	    if (step.op === "quote") {
75	      return { premium: quotePremium(step.items) };
76	    }
77	    return { payout: 0, remainingCap: 0 };
78	  });
79	  return { results };
80	};
